import "./MyRecipe.css";
import { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate, Link } from "react-router-dom";
import UserNavbar from "./UserNavbar";

export default function MyRecipe() {
  const [recipes, setRecipes] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
  const token = localStorage.getItem("token");
  const userId = localStorage.getItem("user_id");

  if (!token || !userId) {
    alert("Please login first ❌");
    navigate("/login");
    return;
  }

  axios
    .get("http://127.0.0.1:8000/api/recipes/", {
      headers: {
        Authorization: `Token ${token}`,
      },
    })
    .then((res) => {
      const myRecipes = res.data
        .filter((recipe) => recipe.created_by === Number(userId))
        .map((recipe) => ({
          ...recipe,
          image: recipe.image
            ? `http://127.0.0.1:8000${recipe.image}`
            : "/default-food.jpg",
          author: "You",
          views: recipe.view_count,
        }));

      setRecipes(myRecipes);
    })
    .catch((err) => {
      console.error("MyRecipe error:", err);
      alert("Failed to load your recipes ❌");
    });
}, [navigate]);

  return (
    <>
      {/* NAVBAR */}
      <UserNavbar />

      {/* MY RECIPES */}
      <div className="recipes-page">
        <h2>My Recipes</h2>

        <div className="recipes-grid">
          {recipes.length === 0 && <p>No recipes added yet.</p>}

          {recipes.map((recipe) => (
            <div className="recipe-card" key={recipe.id}>
              <img src={recipe.image} alt={recipe.title} />

              <div className="recipe-info">
                <h3>{recipe.title}</h3>
                <p>👤 {recipe.author}</p>
                <p>👁 {recipe.views} views</p>

                <Link to={`/recipes/${recipe.id}`} className="view-btn">
                  View Recipe
                </Link>
              </div>
            </div>
          ))}
        </div>
      </div>
    </>
  );
}
